SELECT

FROM sys_user a
WHERE a.id = #{id}

SELECT

FROM sys_user a
WHERE a.login_name = #{loginName}

SELECT

FROM sys_user a
WHERE a.sso_login_name = #{ssoLoginName}

SELECT

FROM sys_user a

    JOIN sys_office query_office ON query_office.id = #{queryOfficeId}
    JOIN sys_office o ON o.id = a.office_id AND o.lft BETWEEN query_office.lft AND query_office.rgt


    a.del_flag = #{DEL_FLAG_NORMAL}

        AND a.login_name LIKE CONCAT('%', #{queryLoginName}, '%')


        AND a.name LIKE CONCAT('%', #{queryName}, '%')


        AND a.enable_flag = #{queryEnableFlag}


        AND a.super_flag = #{querySuperFlag}


ORDER BY a.priority, a.create_date

mapper.update:
UPDATE sys_user
SET last_login_date = #{lastLoginDate},
    last_login_ip   = #{lastLoginIp},
    login_count     = #{loginCount}
WHERE id = #{id}

UPDATE sys_user
SET enable_flag = #{enableFlag},
    login_count = 0,
    update_date = #{updateDate},
    update_by   = #{updateUserId}
WHERE id = #{id}

UPDATE sys_user
SET login_pass  = #{loginPass},
    update_date = #{updateDate},
    update_by   = #{updateUserId}
WHERE id = #{id}

UPDATE sys_user
SET priority = #{priority}
WHERE id = #{id}

